class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> result = new ArrayList<>();
        backtrack(num, result, 0);
        return result;
    }

    private boolean backtrack(String num, List<Integer> result, int start) {
        if (start == num.length() && result.size() >= 3) {
            return true;
        }
        for (int i = start; i < num.length(); i++) {
            if (i > start && num.charAt(start) == '0') {
                break;
            }
            long val = Long.parseLong(num.substring(start, i + 1));
            if (val > Integer.MAX_VALUE) {
                break;
            }
            int size = result.size();
            if (size >= 2 && val > result.get(size - 1) + result.get(size - 2)) {
                break;
            }
            if (size < 2 || val == result.get(size - 1) + result.get(size - 2)) {
                result.add((int) val);
                if (backtrack(num, result, i + 1)) {
                    return true;
                }
                result.remove(result.size() - 1);
            }
        }
        return false;
    }
}
